module edge_detector (  
    input wire clk,  
    input wire rst,  
    input wire signal,  
    output reg edge_detected  
);  
    reg signal_prev;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst) begin  
            edge_detected <= 0;  
            signal_prev <= 0;  
        end else begin  
            edge_detected <= (signal && !signal_prev);  
            signal_prev <= signal;  
        end  
    end  
endmodule
